module counter_5bit_up(
    input clk, rst, load,
    input [4:0] load_value,
    output reg [4:0] q);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (rst)
            q <= 5'b00000;
        else if (load)
            q <= load_value;
        else
            q <= q + 1;
    end
endmodule
